def _difficulty(q):
    ql = q.lower()
    if _re.search(r"\b(a handler|a colleague|a customer|a parent|you (see|find|cut|finish|need|probe|wake|sneeze|are serving)|has (been|sat)|arrives|reads|left (out|warm)|orders|delivery of|spill)\b", ql):
        return "hard"
    if ql.startswith(("what is", "what does", "how many", "which body", "which act", "which unit")):
        return "easy"
    return "medium"


def emit():
    out = []
    qid = 1
    # 1) core bank + scenario additions (topic-keyed)
    for topic, items in DATA.items():
        for q, opts, ans, expl in items:
            assert len(opts) == 4 and 0 <= ans <= 3, f"{topic} q{qid}: bad entry"
            out.append({"id": f"q{qid:03d}", "topic": topic, "question": q,
                        "options": list(opts), "answer": ans, "explanation": expl,
                        "difficulty": _difficulty(q), "state": None})
            qid += 1
        for q, opts, ans, expl in list(SCENARIOS.get(topic, [])) + list(SCENARIOS2.get(topic, [])):
            assert len(opts) == 4 and 0 <= ans <= 3, f"{topic} scenario q{qid}: bad entry"
            out.append({"id": f"q{qid:03d}", "topic": topic, "question": q,
                        "options": list(opts), "answer": ans, "explanation": expl,
                        "difficulty": "hard", "state": None})
            qid += 1
    # 2) state-specific questions (topic: food-standards, tagged with state)
    for code, items in STATE_Q.items():
        for q, opts, ans, expl in items:
            assert len(opts) == 4 and 0 <= ans <= 3
            out.append({"id": f"q{qid:03d}", "topic": "food-standards", "question": q,
                        "options": list(opts), "answer": ans, "explanation": expl,
                        "difficulty": _difficulty(q), "state": code})
            qid += 1
    total = len(out)
    # JSON data file (builder source)
    (ROOT / "tools" / "questions_data.json").write_text(
        json.dumps(out, ensure_ascii=False, indent=1), encoding="utf-8")
    # ES module
    lines = ["// Food Safety Practice Test AU — Question Bank",
             f"// {total} questions aligned with SITXFSA005 / SITXFSA006 & the Food Standards Code",
             "", "export const QUESTIONS = ["]
    for o in out:
        lines.append("    {")
        lines.append(f'        id: "{o["id"]}",')
        lines.append(f'        topic: "{o["topic"]}",')
        lines.append(f'        question: {json.dumps(o["question"], ensure_ascii=False)},')
        lines.append(f'        options: {json.dumps(o["options"], ensure_ascii=False)},')
        lines.append(f'        answer: {o["answer"]},')
        lines.append(f'        explanation: {json.dumps(o["explanation"], ensure_ascii=False)},')
        lines.append(f'        difficulty: "{o["difficulty"]}",')
        if o["state"]:
            lines.append(f'        state: "{o["state"]}",')
        lines.append("    },")
    lines.append("];")
    (ROOT / "questions.js").write_text("\n".join(lines) + "\n", encoding="utf-8")
    # report
    scen = sum(1 for o in out if o["difficulty"] == "hard")
    print("TOTAL:", total)
    print("Unique questions:", len(set(o["question"] for o in out)), "/", total)
    print("Scenario/hard:", scen, f"({round(scen/total*100)}%)")
    print("State-specific:", sum(1 for o in out if o["state"]))

if __name__ == "__main__":
    emit()
